// Collect data from upstream nodes
const actions = $('BQ - Recent Actions').all().map(i => i.json);
const tasks = $('BQ - Open Tasks').all().map(i => i.json);
const health = $('BQ - Connector Health').all().map(i => i.json);

// Helper: convert UTC timestamp to Asia/Riyadh display
function toRiyadh(ts) {
  if (!ts || ts === 'null' || ts === '') return '—';
  try {
    const d = new Date(ts);
    return d.toLocaleString('en-GB', {
      timeZone: 'Asia/Riyadh',
      day: '2-digit', month: 'short', year: 'numeric',
      hour: '2-digit', minute: '2-digit'
    }) + ' AST';
  } catch(e) { return String(ts); }
}

function statusBadge(s) {
  const v = String(s || '').toLowerCase();
  if (v === 'ok' || v === 'success' || v === 'completed' || v === 'done') {
    return `<span class="badge ok">${s}</span>`;
  } else if (v === 'error' || v === 'fail' || v === 'failed') {
    return `<span class="badge err">${s}</span>`;
  } else if (v === 'warning' || v === 'warn' || v === 'in_progress' || v === 'running') {
    return `<span class="badge warn">${s}</span>`;
  }
  return `<span class="badge neutral">${s || '—'}</span>`;
}

function esc(s) {
  return String(s || '').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
}

const now = new Date().toLocaleString('en-GB', {
  timeZone: 'Asia/Riyadh',
  day: '2-digit', month: 'short', year: 'numeric',
  hour: '2-digit', minute: '2-digit'
}) + ' AST';

// Build Recent Actions table rows
const actionRows = actions.length > 0
  ? actions.map(r => `
    <tr>
      <td>${toRiyadh(r.ts)}</td>
      <td><code>${esc(r.role)}</code></td>
      <td>${esc(r.action)}</td>
      <td>${statusBadge(r.status)}</td>
      <td class="detail">${esc(r.detail)}</td>
    </tr>`).join('')
  : '<tr><td colspan="5" class="empty">No activity logged in the last 50 records</td></tr>';

// Build Open Tasks table rows
const taskRows = tasks.length > 0
  ? tasks.map(r => `
    <tr>
      <td>${esc(r.title)}</td>
      <td>${statusBadge(r.status)}</td>
      <td>${esc(r.assignee)}</td>
      <td>${r.due_on ? esc(r.due_on) : '—'}</td>
      <td>${esc(r.priority)}</td>
      <td>${esc(r.section)}</td>
    </tr>`).join('')
  : '<tr><td colspan="6" class="empty">No open tasks</td></tr>';

// Build Connector Health table rows
const healthRows = health.length > 0
  ? health.map(r => {
      const ls = String(r.latest_status || '').toLowerCase();
      const rowClass = ls === 'ok' || ls === 'success' ? '' : (ls === 'error' || ls === 'fail' ? 'row-err' : 'row-warn');
      return `
    <tr class="${rowClass}">
      <td>${esc(r.connector)}</td>
      <td>${esc(r.check_type)}</td>
      <td>${statusBadge(r.latest_status)}</td>
      <td>${r.ok_count}</td>
      <td>${r.error_count}</td>
      <td>${toRiyadh(r.last_seen)}</td>
    </tr>`;
    }).join('')
  : '<tr><td colspan="6" class="empty">No connector health data in last 24h</td></tr>';

const html = `<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<meta http-equiv="refresh" content="3600">
<title>Qoyod Agent Activity</title>
<style>
  *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
  body { font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif; background: #f7f8fa; color: #1a1a2e; font-size: 14px; }
  header { background: #1a1a2e; color: #fff; padding: 20px 32px; display: flex; justify-content: space-between; align-items: center; }
  header h1 { font-size: 20px; font-weight: 600; letter-spacing: 0.3px; }
  header .meta { font-size: 12px; color: #a0aec0; margin-top: 4px; }
  .container { max-width: 1200px; margin: 0 auto; padding: 24px 16px; }
  .section { background: #fff; border-radius: 8px; border: 1px solid #e2e8f0; margin-bottom: 24px; overflow: hidden; }
  .section-header { padding: 14px 20px; border-bottom: 1px solid #e2e8f0; display: flex; align-items: center; gap: 10px; }
  .section-header h2 { font-size: 15px; font-weight: 600; color: #2d3748; }
  .section-header .count { background: #edf2f7; color: #4a5568; font-size: 11px; padding: 2px 8px; border-radius: 10px; font-weight: 500; }
  .table-wrap { overflow-x: auto; }
  table { width: 100%; border-collapse: collapse; }
  th { background: #f7f8fa; text-align: left; padding: 10px 14px; font-size: 11px; font-weight: 600; color: #718096; text-transform: uppercase; letter-spacing: 0.5px; border-bottom: 1px solid #e2e8f0; white-space: nowrap; }
  td { padding: 10px 14px; border-bottom: 1px solid #f0f0f0; vertical-align: top; }
  tr:last-child td { border-bottom: none; }
  tr:hover td { background: #fafbfc; }
  tr.row-err td { background: #fff5f5; }
  tr.row-warn td { background: #fffdf0; }
  .badge { display: inline-block; padding: 2px 8px; border-radius: 10px; font-size: 11px; font-weight: 500; }
  .badge.ok { background: #c6f6d5; color: #22543d; }
  .badge.err { background: #fed7d7; color: #742a2a; }
  .badge.warn { background: #fefcbf; color: #744210; }
  .badge.neutral { background: #e2e8f0; color: #4a5568; }
  .detail { color: #718096; font-size: 12px; max-width: 400px; word-break: break-word; }
  code { font-family: 'SF Mono', 'Fira Code', monospace; background: #edf2f7; padding: 1px 5px; border-radius: 3px; font-size: 12px; }
  .empty { text-align: center; color: #a0aec0; padding: 24px; font-style: italic; }
  footer { text-align: center; padding: 16px; color: #a0aec0; font-size: 12px; }
</style>
</head>
<body>
<header>
  <div>
    <h1>Qoyod Agent Activity</h1>
    <div class="meta">Auto-refreshes every hour &bull; Last updated: ${now}</div>
  </div>
</header>
<div class="container">

  <div class="section">
    <div class="section-header">
      <h2>Recent Agent Actions</h2>
      <span class="count">${actions.length} rows</span>
    </div>
    <div class="table-wrap">
      <table>
        <thead><tr>
          <th>Timestamp (AST)</th><th>Role</th><th>Action</th><th>Status</th><th>Detail</th>
        </tr></thead>
        <tbody>${actionRows}</tbody>
      </table>
    </div>
  </div>

  <div class="section">
    <div class="section-header">
      <h2>Open Tasks</h2>
      <span class="count">${tasks.length} open</span>
    </div>
    <div class="table-wrap">
      <table>
        <thead><tr>
          <th>Title</th><th>Status</th><th>Assignee</th><th>Due</th><th>Priority</th><th>Section</th>
        </tr></thead>
        <tbody>${taskRows}</tbody>
      </table>
    </div>
  </div>

  <div class="section">
    <div class="section-header">
      <h2>Connector Health (Last 24h)</h2>
      <span class="count">${health.length} connectors</span>
    </div>
    <div class="table-wrap">
      <table>
        <thead><tr>
          <th>Connector</th><th>Check Type</th><th>Latest Status</th><th>OK Checks</th><th>Error Checks</th><th>Last Seen (AST)</th>
        </tr></thead>
        <tbody>${healthRows}</tbody>
      </table>
    </div>
  </div>

</div>
<footer>Qoyod Performance Agent &bull; <a href="https://qoyod.app.n8n.cloud" style="color:#a0aec0">n8n Cloud</a> &bull; Updated ${now}</footer>
</body>
</html>`;

// Base64 encode for GitHub API
const base64 = Buffer.from(html).toString('base64');

return [{ json: { html, base64 } }];
